/// Look for patterns like
///   %sel1 = select i1 %c1, i32 %a, i32 %b
///   %sel2 = select i1 %c1, i32 %b, i32 %a
///   %ret = select i1 %c2, i32 %sel1, i32 %sel2
/// and optimize it to:
///   %ret = select i1 %c1 ^ %c2, i32 %b, i32 %a
static Instruction *foldSymmetricSelects(SelectInst &Sel, InstCombiner::BuilderTy &Builder) {
  // Decompose outer select: %ret = select %c2, %sel1, %sel2
  Value *OuterCond = Sel.getCondition();
  Value *TrueVal = Sel.getTrueValue();
  Value *FalseVal = Sel.getFalseValue();

  SelectInst *Sel1 = dyn_cast<SelectInst>(TrueVal);
  SelectInst *Sel2 = dyn_cast<SelectInst>(FalseVal);
  if (!Sel1 || !Sel2)
    return nullptr;

  // Check both selects use the same condition
  if (Sel1->getCondition() != Sel2->getCondition())
    return nullptr;
  Value *InnerCond = Sel1->getCondition();

  // Check that the true/false values are swapped
  if (Sel1->getTrueValue() != Sel2->getFalseValue() || 
      Sel1->getFalseValue() != Sel2->getTrueValue())
    return nullptr;

  // Now we have:
  //   sel1 = select %inner.c, %a, %b
  //   sel2 = select %inner.c, %b, %a
  //   ret  = select %outer.c, sel1, sel2
  // This is equivalent to: select (%inner.c ^ %outer.c), %b, %a
  Value *XorCond = Builder.CreateXor(InnerCond, OuterCond);
  Value *A = Sel1->getFalseValue();  // %b in sel1, which becomes false when inner.c is true
  Value *B = Sel1->getTrueValue();   // %a in sel1, which becomes true when inner.c is true
  return SelectInst::Create(XorCond, A, B);
}

